    private final RestTemplate restTemplate;

    private static final Set<String> ALLOWED_PROTOCOLS = Collections.unmodifiableSet(
            new HashSet<>(Arrays.asList("http", "https")));

    @Autowired
    public WebPageFetcherService(RestTemplate restTemplate) {
        this.restTemplate = restTemplate;
    }

    /**
     * Fetches the HTML content of the page at the provided URL.
     * This method is intended for retrieving data from the public internet.
     * It validates the protocol and ensures the target host is not an internal IP address.
     *
